import xml.etree.ElementTree as ET

def validate_xml(file):
    root = ET.parse(file).getroot()
    # Check if the root element is valid
    if root.tag != 'data':
        raise ValueError('Invalid root element')
    # Check if all child elements are valid
    for child in root:
        if child.tag not in ['item', 'quantity']:
            raise ValueError('Invalid child element')
    # Check if the attributes of each item element are valid
    for item in root.findall('.//item'):
        if item.attrib['id'] == '' or item.attrib['name'] == '':
            raise ValueError('Invalid item attribute')
    return True